class Solution:
    def numSub(self, s: str) -> int:
        MOD = 10 ** 9 + 7
        n = len(s)
        if n <= 3000:
            total = 0
            for i in range(n):
                if s[i] == '0':
                    continue
                for j in range(i, n):
                    if s[j] == '0':
                        break
                    total += 1
            return total % MOD
        import itertools
        total = 0
        for ch, grp in itertools.groupby(s):
            if ch == '1':
                length = sum(1 for _ in grp)
                total += length * (length + 1) // 2
        return total % MOD

