var numSub = function(s) {
    const MOD = 1000000007;
    let total = 0;
    let run = 0;
    for (const ch of s) {
        if (ch === '1') {
            run += 1;
            total = (total + run) % MOD;
        } else {
            run = 0;
        }
    }
    return total;
};
